class Solution {
public:
    char kthCharacter(long long k, vector<int>& operations) {
        long long len = 1;
        vector<long long> lengths = {1};
        for (int op : operations) {
            if (op == 0) {
                len *= 2;
            } else {
                len = 2 * len + len;
            }
            lengths.push_back(len);
        }
        int shift = 0;
        for (int i = operations.size() - 1; i >= 0; --i) {
            long long half = lengths[i];
            if (k > half) {
                if (operations[i] == 1) {
                    shift += (k - half - 1) % 26;
                }
                k -= half;
            }
        }
        return 'a' + (shift % 26);
    }
};
```
efficiency: HIGH
time complexity: O(N)
space complexity: O(N)
energy implications: LOW
explanation: Work backwards from the final string length. For each operation, determine whether k falls in the first or second half. If it's in the second half and the operation is type 1, accumulate the shift for the corresponding character. The shift is computed modulo 26 to handle wrap-around from 'z' to 'a'.

